<template>
  <div class="songs-cont">
    <div class="tab-bar">
      <ul>
        <li :class="{ active: tag == '0' }" @click="tag = '0'">全部</li>
        <li :class="{ active: tag == '7' }" @click="tag = '7'">华语</li>
        <li :class="{ active: tag == '96' }" @click="tag = '96'">欧美</li>
        <li :class="{ active: tag == '8' }" @click="tag = '8'">日本</li>
        <li :class="{ active: tag == '16' }" @click="tag = '16'">韩国</li>
      </ul>
    </div>
    <!-- table -->
    <table class="el-table playlit-table">
      <thead>
        <th></th>
        <th></th>
        <th>音乐标题</th>
        <th>歌手</th>
        <th>专辑</th>
        <th>时长</th>
      </thead>
      <tbody>
        <tr v-for="(item,i) in musicList" :key="i">
          <td>{{i+1}}</td>
          <td>
            <div class="img-wrap">
              <img :src="item.album.picUrl" alt="" />
              <span class="iconfont icon-icon_play_default" @click="playMusic(item.id)"></span>
            </div>
          </td>
          <td>
            <div class="song-wrap">
              <div class="name-wrap">
                <span>{{item.album.name}}</span>
                <span class="iconfont icon-MV"></span>
              </div>
              <p>{{item.album.company}}</p>
            </div>
          </td>
          <td>{{item.artists[0].name}}</td>
          <td>{{item.name}}</td>
          <td>{{item.duration|getGapTime}}</td>
        </tr>
      </tbody>
    </table>
  </div>
</template>
<script>
import music from "@/api/music"
export default {
  name:'songs',
  data() {
    return {
      tag: "0",
      musicList:[]
    };
  },
  watch:{
    tag(){
      this.goMusicList()
    }
  },
  methods:{
    async playMusic(id){
      const res = await music.playMusicList({
        params:{
          id
        }
      })
      if(res.data[0].url == null) {
        this.$message('版权方要求，当前专辑需单独付费，购买数字专辑即可无限畅享');
      }else{
        this.$parent.$data.url = res.data[0].url
      }
    },
    async goMusicList(){
      const res = await music.getMusicList({
        params:{
          type:this.tag
        }
      })
      res.data.map(v=>{
        if(v.artists.length==2){
          v.artists[0].name = v.artists[0].name + '/' + v.artists[1].name
        }else if(v.artists.length==3){
          v.artists[0].name = v.artists[0].name + '/' + v.artists[1].name + '/' +v.artists[2].name
        }
      })
      this.musicList = res.data.slice(1,20)
    }
  },
  created(){
    this.goMusicList()
  }
};
</script>

<style lang='scss' scoped>
.songs-cont {
  .tab-bar {
    ul {
      display: flex;
      justify-content: flex-end;
      li {
        margin-right: 20px;
        cursor: pointer;
      }
      .active {
        color: #dd6d60;
      }
    }
  }
  .el-table {
    .song-wrap {
      .name-wrap {
        margin-bottom: 20px;
        .icon-MV {
          padding-left: 5px;
          color: #dd6d60;
        }
      }
      p {
        color: #bebebe;
      }
    }
  }
}
</style>